const data = items[0].json;

// Sort function: longest duration first
const sortByDuration = (a, b) => {
  const durationA = a.durationDays || 0;
  const durationB = b.durationDays || 0;
  return durationB - durationA; // Descending order (longest first)
};

// Sort the requests by duration
const sortedOngoing = [...data.ongoing.requests].sort(sortByDuration);
const sortedResolved = [...data.resolved.requests].sort(sortByDuration);

// Build Slack message with markdown formatting
let slackMessage = `*Daily STP Report - ${data.reportDate}*\n\n`;

// Summary section
slackMessage += `*SUMMARY*\n`;
slackMessage += `• Ongoing Requests: *${data.ongoing.count}*\n`;
slackMessage += `• Resolved Requests: *${data.resolved.count}*\n`;
slackMessage += `• Total Processed: *${data.totalProcessed}*\n`;
slackMessage += `\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n\n`;

// Ongoing STP Requests (NOW FIRST!)
slackMessage += ` *ONGOING STP REQUESTS: ${data.ongoing.count}*\n`;
slackMessage += `_(Sorted by duration: longest first)_\n\n`;

if (data.ongoing.count > 0) {
  sortedOngoing.forEach((req, index) => {
    slackMessage += `*${index + 1}. ${req.stpCode}*\n`;
    slackMessage += `   • Status: ${req.status}\n`;
    slackMessage += `   • Duration: *${req.durationDays || 'N/A'} days* since request\n`;
    slackMessage += `   • Candidates Endorsed: *${req.endorsementCount}*\n`;

    if (req.candidates.length > 0) {
      slackMessage += `   • Endorsed Candidates:\n`;
      req.candidates.forEach((candidate, idx) => {
        slackMessage += `      ${idx + 1}. \`${candidate.vaId}\` - Endorsed: ${candidate.endorsedDate}\n`;
      });
    }
    slackMessage += `\n`;
  });
} else {
  slackMessage += `_No ongoing requests_\n\n`;
}

slackMessage += `━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n\n`;

// Resolved STP Requests (NOW SECOND!)
slackMessage += ` *RESOLVED STP REQUESTS: ${data.resolved.count}*\n`;
slackMessage += `_(Sorted by duration: longest first)_\n\n`;

if (data.resolved.count > 0) {
  sortedResolved.forEach((req, index) => {
    slackMessage += `*${index + 1}. ${req.stpCode}*\n`;
    slackMessage += `   • Status: ${req.status}\n`;
    slackMessage += `   • Duration: *${req.durationDays || 'N/A'} days*\n`;
    slackMessage += `   • Candidates Endorsed: *${req.endorsementCount}*\n`;

    if (req.candidates.length > 0) {
      slackMessage += `   • Endorsed Candidates:\n`;
      req.candidates.forEach((candidate, idx) => {
        slackMessage += `      ${idx + 1}. \`${candidate.vaId}\` - Endorsed: ${candidate.endorsedDate}\n`;
      });
    }
    slackMessage += `\n`;
  });
} else {
  slackMessage += `_No resolved requests today_\n\n`;
}

slackMessage += `━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n`;
slackMessage += `_Report Generated: ${data.reportTimestamp}_`;

// Return formatted message
return [
  {
    json: {
      text: slackMessage
    }
  }
];

