// Plain text version for email clients that don't support HTML
let emailPlainText = `Weekly STP Report - ${data.reportDate}\n\n`;
emailPlainText += `RESOLVED STP REQUESTS: ${data.resolved.count}\n`;
emailPlainText += `ONGOING STP REQUESTS: ${data.ongoing.count}\n\n`;
emailPlainText += `Total Records Processed: ${data.totalProcessed}`;

return [
