const data = items[0].json;

// Helper function to format dates to MMM-DD-YYYY
const formatDateToMMM_DD_YYYY = (dateString) => {
  if (!dateString || dateString === 'N/A') return 'N/A';

  // Try to parse the date string
  const date = new Date(dateString);
  if (isNaN(date.getTime())) return dateString; // Return original if parsing fails

  const months = ['Jan', 'Feb', 'Mar', 'Apr', 'May', 'Jun', 'Jul', 'Aug', 'Sep', 'Oct', 'Nov', 'Dec'];
  const month = months[date.getMonth()];
  const day = String(date.getDate()).padStart(2, '0');
  const year = date.getFullYear();

  return `${month}-${day}-${year}`;
};

// Sort helper
const sortByDuration = (a, b) => (b.durationDays || 0) - (a.durationDays || 0);

// Ongoing only, sorted by duration
const ongoingRequests = (data.ongoing?.requests || []).sort(sortByDuration);

// Helper function to determine RAG color
const getRAGColor = (days) => {
  if (!days || days === 0) return '#6E86AD'; // Scale Virtually Grey
  if (days > 30) return '#dc2626'; // Red
  if (days > 14) return '#F17D19'; // Scale Virtually Orange (Amber)
  return '#10b981'; // Green
};

// Helper function to get RAG emoji for Slack
const getRAGEmoji = (days) => {
  if (!days || days === 0) return '⚪'; // White circle for N/A
  if (days > 30) return '🔴'; // Red
  if (days > 14) return '🟠'; // Orange/Amber
  return '🟢'; // Green
};

// Use human-readable date from data and convert to MMM-DD-YYYY format
const formattedDate = formatDateToMMM_DD_YYYY(data.reportDateFormatted);

// Get average durations
const avgOngoingDuration = data.averageDurations?.ongoing || 0;
const avgResolvedDuration = data.averageDurations?.resolved || 0;

// === BUILD SLACK MESSAGE ===
const ongoingRAG = getRAGEmoji(avgOngoingDuration);
const resolvedRAG = getRAGEmoji(avgResolvedDuration);

const slackMessage = `Hi Team - Here's the STP report as of ${formattedDate}

*Ongoing Requests:* ${data.ongoing?.count || 0} | *Avg Duration:* ${avgOngoingDuration} days ${ongoingRAG}
*Completed Requests:* ${data.resolved?.count || 0} | *Avg Duration:* ${avgResolvedDuration} days ${resolvedRAG}`;

// HTML build
const htmlContent = `
