    border-bottom: 1px solid #e5e7eb;
  }
  .candidate-item:last-child { border-bottom: none; }
  .candidate-item .va-name {
    color: #1f2937;
    font-weight: 600;
  }
  .candidate-item .date {
    color: #6E86AD;
    font-size: 12px;
  }
  .footer {
    padding: 25px;
    background: #FFFFFF;
    text-align: center;
