          <g fill="#3d3d3d">
            <text x="350" y="70" font-family="Arial, sans-serif" font-size="75" font-weight="700" letter-spacing="-2" text-anchor="middle">SCALE</text>
          </g>

          <!-- VIRTUALLY Text (Orange) -->
          <g fill="#F17D19">
            <text x="350" y="120" font-family="Arial, sans-serif" font-size="45" font-weight="700" letter-spacing="2" text-anchor="middle">VIRTUALLY</text>
          </g>
        </svg>
      </div>
      <h1>📊 Daily STP Report</h1>
      <div class="date">As of ${formattedDate}</div>
    </div>

    <div class="summary">
      <div class="summary-item ongoing">
        <div class="label">Ongoing Requests</div>
        <div class="value">${data.ongoing?.count || 0}</div>
        <div class="sub-value" style="color: ${getRAGColor(avgOngoingDuration)};">
          Avg: ${avgOngoingDuration} days
        </div>
      </div>
      <div class="summary-item resolved">
        <div class="label">Resolved Requests</div>
        <div class="value">${data.resolved?.count || 0}</div>
        <div class="sub-value" style="color: ${getRAGColor(avgResolvedDuration)};">
          Avg: ${avgResolvedDuration} days
        </div>
      </div>
      <div class="summary-item">
        <div class="label">Total Processed</div>
        <div class="value">${data.totalProcessed || 0}</div>
      </div>
    </div>

    <div class="main">
      <div class="section-header">
        <h2>🔄 Ongoing STP Requests</h2>
        <div class="count">${data.ongoing?.count || 0}</div>
      </div>
      <div class="section-note">📌 Sorted by duration: longest first | ✅ Only showing requests with endorsed candidates</div>
      <div class="grid">
        ${ongoingRequests.map((req, i) => {
          const d = req.durationDays || 0;
          const durationColor = getRAGColor(d);
          const statusClass = (req.status || '').toLowerCase().replace(/\s+/g, '-').replace(/[^a-z0-9-]/g, '');
          const placementReq = req.placementRequirement || 'N/A';

          return `
            <div class="request-item">
              <div class="request-header">
                <div class="req-title">${i + 1}. ${req.stpCode || 'N/A'}</div>
                <div class="req-subtitle">Placement Requirement: ${placementReq}</div>
                <span class="status-badge ${statusClass}">${req.status || 'N/A'}</span>
              </div>

              <div class="info-row">
                <span class="info-label">DURATION:</span>
                <span class="duration-badge" style="background-color: ${durationColor}20; color: ${durationColor}; border: 1px solid ${durationColor};">
                  ${d > 0 ? d + ' days' : 'N/A'}
                </span>
              </div>

              <div class="info-row">
                <span class="info-label">REQUEST DATE:</span>
                <span class="info-value">${formatDateToMMM_DD_YYYY(req.requisitionDate)}</span>
              </div>

              <div class="info-row">
                <span class="info-label">CANDIDATES:</span>
                <span class="info-value">${req.endorsementCount || 0} endorsed</span>
              </div>

              ${req.candidates?.length ? `
                <div class="candidates">
                  <div class="candidates-title">✓ Endorsed Candidates (${req.candidates.length})</div>
                  ${req.candidates.map((c, idx) => `
                    <div class="candidate-item">
                      <span class="va-name">${idx + 1}. ${c.vaId || 'N/A'}</span>
                      <span class="date">📅 ${formatDateToMMM_DD_YYYY(c.endorsedDate)}</span>
                    </div>
                  `).join('')}
                </div>
              ` : ''}
            </div>
          `;
        }).join('')}
      </div>
    </div>

    <div class="footer">
      <strong>Report Generated:</strong> ${data.reportTimestamp || 'N/A'}
    </div>
  </div>
</body>
</html>
`;

return [
  { 
    json: { 
      html: htmlContent,
      slackMessage: slackMessage,
      reportMetadata: {
        date: formattedDate,
        ongoingCount: data.ongoing?.count || 0,
        ongoingAvgDuration: avgOngoingDuration,
        ongoingRAG: ongoingRAG,
        resolvedCount: data.resolved?.count || 0,
        resolvedAvgDuration: avgResolvedDuration,
        resolvedRAG: resolvedRAG,
      }
    } 
  }
];

// === STEP 1: Get Airtable Data Safely ===
let stpRecords;
// Handle different formats of Airtable responses
if (Array.isArray(items)) {
  if (Array.isArray(items[0].json)) {
    stpRecords = items[0].json;
  } else if (items[0].json.records && Array.isArray(items[0].json.records)) {
    stpRecords = items[0].json.records.map(r => r.fields); // Airtable standard format
  } else if (items[0].json.data && Array.isArray(items[0].json.data)) {
    stpRecords = items[0].json.data;
  } else if (items.length > 1) {
    stpRecords = items.map(i => i.json);
  } else {
    stpRecords = [items[0].json];
  }
} else {
  throw new Error("Unexpected data structure — check Airtable output.");
}

// If still undefined, abort early
if (!stpRecords || !stpRecords.length) {
  throw new Error("No STP records found — Airtable may have returned empty data.");
}

// === HELPER: Format date to human-readable format ===
function formatDateHuman(dateString) {
  if (!dateString) return "N/A";

  try {
    const date = new Date(dateString);
    if (isNaN(date)) return "N/A";

    // Format: November 10, 2025
    const options = { year: 'numeric', month: 'long', day: 'numeric' };
    return date.toLocaleDateString('en-US', options);
  } catch (error) {
    return "N/A";
  }
}

// === STEP 2: Initialize Counters ===
let resolvedCount = 0;
let ongoingCount = 0;
let resolvedCandidates = [];
let ongoingCandidates = [];

// === Track durations for averages ===
let ongoingDurations = [];
let resolvedDurations = [];

// === STEP 3: Process Each Record ===
for (const record of stpRecords) {
  if (!record) continue;

  const statusRaw = record["Requisition Status"] || "N/A";
  const status = String(statusRaw).trim();
  const stpCode = record["STP Code"] || record["STP Request ID"] || "N/A";
  const requisitionDate = record["Requisition Date"] || null;

  // === Use TEXT fields instead of IDs ===
  const endorsedVAsText = record["Endorsed VAs (text)"] || [];
  const placementReqsText = record["Placements Requirements (text)"] || [];
  const endorsedDates = Array.isArray(record["Endorsed to Placements"]) ? record["Endorsed to Placements"] : [];

  // === Check if the status is considered 'Ongoing' ===
  const isOngoing = /ongoing|requested/i.test(status);

  // === REVISED FILTER: Keep ALL Ongoing STPs. Skip others only if missing requirements ===
  if (!isOngoing && (!Array.isArray(placementReqsText) || placementReqsText.length === 0)) {
    continue; // Skip ONLY if it's a Resolved/Other status AND has no placement requirements
  }

  // === Extract Placement Requirement (TEXT) ===
  let placementRequirement = "N/A";
